-- Canonical DDL for naap.api_hourly_streaming_sla_store.
-- Source of truth: this file. The resolver and MVs write rows;
-- this declaration governs the physical schema.
-- Apply with scripts/apply-store-ddl.sh; drift is caught by
-- warehouse/tests/test_store_ddl_drift.sql.

CREATE TABLE IF NOT EXISTS naap.api_hourly_streaming_sla_store (`window_start` DateTime('UTC'), `org` Nullable(String) DEFAULT CAST(NULL, 'Nullable(String)'), `orchestrator_address` String, `orchestrator_uri` String DEFAULT '', `pipeline_id` String, `model_id` Nullable(String), `gpu_id` Nullable(String), `gpu_model_name` Nullable(String) DEFAULT CAST(NULL, 'Nullable(String)'), `region` Nullable(String), `known_sessions_count` UInt64, `requested_sessions` UInt64 DEFAULT 0, `startup_success_sessions` UInt64, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64, `startup_failed_sessions` UInt64 DEFAULT 0, `loading_only_sessions` UInt64 DEFAULT 0, `zero_output_fps_sessions` UInt64 DEFAULT 0, `output_failed_sessions` UInt64 DEFAULT 0, `effective_failed_sessions` UInt64 DEFAULT 0, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `startup_success_rate` Nullable(Float64), `excused_failure_rate` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `effective_success_rate` Nullable(Float64), `no_swap_rate` Nullable(Float64), `output_viability_rate` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `output_fps_sum` Float64 DEFAULT 0, `status_samples` UInt64 DEFAULT 0, `avg_output_fps` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `prompt_to_first_frame_sum_ms` Float64 DEFAULT 0, `prompt_to_first_frame_sample_count` UInt64 DEFAULT 0, `avg_prompt_to_first_frame_ms` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `e2e_latency_sum_ms` Float64 DEFAULT 0, `e2e_latency_sample_count` UInt64 DEFAULT 0, `avg_e2e_latency_ms` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `reliability_score` Nullable(Float64) DEFAULT CAST(NULL, 'Nullable(Float64)'), `ptff_score` Float64 DEFAULT 0, `e2e_score` Float64 DEFAULT 0, `latency_score` Float64 DEFAULT 0, `fps_score` Float64 DEFAULT 0, `quality_score` Float64 DEFAULT 0, `sla_semantics_version` String DEFAULT '', `sla_score` Nullable(Float64), `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY toYYYYMM(window_start) ORDER BY (window_start, orchestrator_address, pipeline_id, ifNull(model_id, ''), ifNull(gpu_id, ''), ifNull(region, ''), refreshed_at) SETTINGS index_granularity = 8192;
